import agno
from contextlib import contextmanager

def tool_loop_detector(max_calls=15):
    @contextmanager
    def limiter(agent):
        agent.metrics['tool_calls'] = 0

        original_tool_call = agent._call_tool

        def limited_tool_call(tool_name, *args, **kwargs):
            agent.metrics['tool_calls'] += 1
            if agent.metrics['tool_calls'] > max_calls:
                raise Exception(f'Tool loop: exceeded {max_calls} tool calls')
            return original_tool_call(tool_name, *args, **kwargs)

        agent._call_tool = limited_tool_call
        try:
            yield agent
        finally:
            agent._call_tool = original_tool_call

    return limiter

import hashlib
import agno

def detect_state_cycles(agent):
    seen_states = set()

    def hash_agent_state():
        state_str = str({
            'memory': agent.session.memory.keys(),
            'last_tools': [t.name for t in agent.session.trace[-3:]],
            'task': agent.current_task
        })
        return hashlib.md5(state_str.encode()).hexdigest()

    original_step = agent._step

    def tracked_step(*args, **kwargs):
        state_hash = hash_agent_state()
        if state_hash in seen_states:
            raise Exception(f'State cycle detected: {state_hash} repeated')
        seen_states.add(state_hash)
        return original_step(*args, **kwargs)

    agent._step = tracked_step
    return agent

