import agno

def progressive_tool_costs(agent):
    tool_usage = {}

    def weighted_tool_selection(tools, llm):
        for tool in tools:
            usage_count = tool_usage.get(tool.name, 0)
            tool.description += f" (used {usage_count} times - consider alternatives)"
            tool_usage[tool.name] = usage_count + 1

        return agent.llm.acall([
            'Select best tool',
            'Avoid recently used tools',
            'Break potential loops'
        ], tools=tools)

    agent._select_tool = weighted_tool_selection
    return agent
